VCN com subnets:

```hcl
resource "oci_core_vcn" "main" {
  compartment_id = var.compartment_ocid
  cidr_block     = "10.0.0.0/16"
  display_name   = "main-vcn"
  dns_label      = "mainvcn"
}

resource "oci_core_internet_gateway" "ig" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.main.id
  display_name   = "main-ig"
}

resource "oci_core_nat_gateway" "nat" {
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.main.id
  display_name   = "main-nat"
}

resource "oci_core_subnet" "public" {
  vcn_id         = oci_core_vcn.main.id
  cidr_block     = "10.0.1.0/24"
  route_table_id = oci_core_route_table.public.id
}

resource "oci_core_subnet" "private" {
  vcn_id         = oci_core_vcn.main.id
  cidr_block     = "10.0.2.0/24"
  route_table_id = oci_core_route_table.private.id
}
```

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Security Lists e NSGs:

**Security List (nível subnet):**
```hcl
resource "oci_core_security_list" "web" {
  vcn_id = oci_core_vcn.main.id
  ingress_security_rules {
    protocol = "6"  # TCP
    source   = "0.0.0.0/0"
    tcp_options { max = 443; min = 443 }
  }
  ingress_security_rules {
    protocol = "6"
    source   = "0.0.0.0/0"
    tcp_options { max = 80; min = 80 }
  }
}
```

**NSG (nível VNIC, mais granular):**
```hcl
resource "oci_core_network_security_group" "db_nsg" {
  vcn_id = oci_core_vcn.main.id
}

resource "oci_core_network_security_group_security_rule" "db_rule" {
  network_security_group_id = oci_core_network_security_group.db_nsg.id
  direction = "INGRESS"
  protocol  = "6"
  source    = "10.0.1.0/24"  # Apenas da subnet de app
  tcp_options { destination_port_max = 1521; destination_port_min = 1521 }
}
```

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

VCN Peering:

```hcl
resource "oci_core_vcn" "vcn_a" {
  cidr_block = "10.0.0.0/16"
}

resource "oci_core_vcn" "vcn_b" {
  cidr_block = "10.1.0.0/16"
}

resource "oci_core_local_peering_gateway" "lpg_a" {
  vcn_id    = oci_core_vcn.vcn_a.id
  peer_id   = oci_core_local_peering_gateway.lpg_b.id
}

resource "oci_core_local_peering_gateway" "lpg_b" {
  vcn_id = oci_core_vcn.vcn_b.id
}
```

**Route tables:** Adicione regra apontando para o LPG com CIDR da VCN remota

**Requisito:** CIDRs não podem sobrepor

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

DNS para VCN:

```hcl
resource "oci_core_vcn" "main" {
  dns_label = "mainvcn"
}

resource "oci_core_subnet" "public" {
  dns_label = "public"
}

resource "oci_core_instance" "web" {
  create_vnic_details {
    hostname_label = "web01"  # web01.public.mainvcn.oraclevcn.com
  }
}
```

**Custom DNS resolver:**
```hcl
resource "oci_dns_resolver" "custom" {
  compartment_id  = var.compartment_ocid
  attached_vcn_id = oci_core_vcn.main.id
  rules {
    rule_type = "RESOLVING"
    domain    = "corp.local."
    forward { forward_address = "10.100.0.53" }
  }
}
```

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Service Gateway + NAT Gateway:

**NAT Gateway (saída internet para subnets privadas):**
```hcl
resource "oci_core_nat_gateway" "nat" {
  vcn_id = oci_core_vcn.main.id
}
```

**Service Gateway (acesso a serviços OCI sem internet):**
```hcl
data "oci_core_services" "all" {
  filter { name = "name"; values = ["All .* Services In Oracle Services Network"]; regex = true }
}

resource "oci_core_service_gateway" "sg" {
  vcn_id   = oci_core_vcn.main.id
  services { service_id = data.oci_core_services.all.services[0].id }
}
```

**Route table privada:**
```hcl
route_rules {
  destination      = "0.0.0.0/0"
  network_entity_id = oci_core_nat_gateway.nat.id
}
route_rules {
  destination      = data.oci_core_services.all.services[0].cidr_block
  destination_type = "SERVICE_CIDR_BLOCK"
  network_entity_id = oci_core_service_gateway.sg.id
}
```

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs

Remote Peering (cross-region):

```hcl
# Ashburn
provider "oci" { alias = "ashburn"; region = "us-ashburn-1" }

resource "oci_core_remote_peering_connection" "ashburn" {
  provider       = oci.ashburn
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.ashburn.id
}

# São Paulo
provider "oci" { alias = "saopaulo"; region = "sa-saopaulo-1" }

resource "oci_core_remote_peering_connection" "saopaulo" {
  provider       = oci.saopaulo
  compartment_id = var.compartment_ocid
  vcn_id         = oci_core_vcn.saopaulo.id
  peer_id        = oci_core_remote_peering_connection.ashburn.id
}
```

Route tables: adicione regras apontando para RPC com CIDR da região remota

Doc: https://registry.terraform.io/providers/oracle/oci/latest/docs
